+    fn simple_chain() -> WeightedGraph {
+        // 0 -1-> 1 -2-> 2 -3-> 3
+        WeightedGraph::from_edges(4, &[(0, 1, 1.0), (1, 2, 2.0), (2, 3, 3.0)])
+    }
+
+    fn diamond_graph() -> WeightedGraph {
+        //     0
+        //    / \
+        //   1   4
+        //  / \
+        // 1   2
+        //  \ /
+        //   3
+        //   3
+        WeightedGraph::from_edges(
+            4,
+            &[
+                (0, 1, 1.0),
+                (0, 2, 4.0),
+                (1, 3, 5.0),
